 25	        GeometryReader { proxy in
 26	            ScrollView(.vertical) {
 27	                VStack(spacing: .zero) {
 28	                    VStack(spacing: .zero) {
 29	                        HeaderView(viewModel: self.viewModel.headerViewModel)
 30	                            .padding(.bottom, 24.0)
 31	                        Divider()
 32	                        WeeklyCarrouselView(viewModel: self.viewModel.weeklyCarrouselViewModel)
 33	                        // Container relative frame not working on first pass
 34	                            .scrollTargetLayout()
 35	                    }
 36	                    .frame(height: proxy.size.height - self.bottomSectionOffset)
 37	                    self.bottomSection
 38	                }
 39	                .animation(.default, value: self.viewModel.onboardingChecklistViewModel.shouldShow)
 40	            }
 41	
 42	            .scrollPosition(self.$viewModel.scrollPosition)
 43	            .scrollBounceBehavior(.basedOnSize, axes: .vertical)
 44	            .scrollIndicators(.hidden)
 45	        }
 46	        .fillSpace()
 47	        .background {
 48	            Theme.Color.white
 49	                .ignoresSafeArea()
 50	        }
 51	        .ignoresSafeArea(.keyboard)
 52	        .onAppear {
 53	            self.viewModel.onAppear()
 54	        }
 55	    }
 56	
 57	    @ViewBuilder private var bottomSection: some View {
 58	        Group {
 59	            switch self.viewModel.bottomContent {
 60	            case .checklist:
 61	                OnboardingChecklistView(viewModel: self.viewModel.onboardingChecklistViewModel) {
 62	                    self.viewModel.scrollToBottom()
 63	                }
 64	                .transition(.asymmetric(insertion: .identity,
 65	                                        removal: AnyTransition(self.onboardingChecklistRemovalTransition)))
 66	            case let .announcement(data):
 67	                BasicButton {
 68	                    Haptics.vibrate(.light)
 69	                    self.viewModel.didTapAnnouncementPill()
 70	                } label: {
 71	                    AnnouncementPillView(viewData: data)
 72	                }
 73	            case .none:
 74	                EmptyView()
 75	            }
 76	        }
 77	        .padding(.horizontal, Theme.Spacer.large)
 78	        .padding(.bottom, Theme.Spacer.large)
 79	    }
 80	
 81	    private var onboardingChecklistRemovalTransition: any Transition {
 82	        switch self.viewModel.bottomContent {
 83	        case .announcement: return .opacity.combined(with: .move(edge: .bottom))
 84	        case .checklist, .none: return .opacity
 85	        }
 86	    }
 87	
 88	    private var bottomSectionOffset: CGFloat {
 89	        switch self.viewModel.bottomContent {
 90	        case .none: return .zero
 91	        case .checklist, .announcement:
 92	            return Info.Device.shouldUseCompactLayout
 93	                ? Theme.Spacer.large
 94	                : OnboardingChecklistView.collapsedHeight + Theme.Spacer.large
 95	        }
 96	    }
 97	}
